css:
/* INVOICE PAGE */
.print-format-content {
    font-family: "Helvetica Neue", Helvetica, Arial, sans-serif;
    color: #263443;
    font-size: 10px;
    line-height: 1.45;
    padding-bottom: 32mm;
}

.print-format {
    min-height: 250mm;
    position: relative;
    padding-bottom: 34mm;
}

.header-top-section {
    margin-bottom: 18px;
    border-bottom: 2px solid #263f55;
    padding-bottom: 8px;
}

.firm-letterhead h2 {
    color: #155d63;
    font-size: 20px;
    margin: 0;
}

.firm-letterhead p {
    color: #65737e;
    margin: 2px 0 0;
}

.invoice-title-block {
    text-align: right;
    padding-top: 8px;
}

.invoice-title-block h1 {
    color: #263f55;
    font-size: 25px;
    font-weight: 500;
    margin: 0;
    text-transform: uppercase;
}

.status-badge {
    background: #eef1f3;
    border-radius: 3px;
    display: inline-block;
    font-size: 8px;
    margin-top: 4px;
    padding: 3px 7px;
    text-transform: uppercase;
}

.recipient-section {
    margin-bottom: 18px;
}

.label-text {
    color: #6f7c86;
    display: block;
    font-size: 8px;
    font-weight: 600;
    margin: 0 0 2px;
    text-transform: uppercase;
}

.customer-name {
    font-size: 13px;
    font-weight: 700;
    margin: 0 0 3px;
}

.recipient-address,
.recipient-line {
    color: #46545f;
    margin: 1px 0;
}

.case-reference {
    background: #f5f7f8;
    border-left: 3px solid #155d63;
    margin-top: 8px;
    padding: 6px 8px;
    width: 78%;
}

.invoice-meta {
    text-align: right;
}

.invoice-meta p {
    margin: 0 0 5px;
}

.invoice-meta strong {
    display: block;
    font-size: 10px;
}

.legal-table {
    border-collapse: collapse;
    margin-top: 10px;
    width: 100%;
}

.legal-table th {
    background: #263f55;
    color: #fff;
    font-size: 8px;
    font-weight: 600;
    padding: 7px 8px;
    text-align: left;
    text-transform: uppercase;
}

.legal-table td {
    border-bottom: 1px solid #dfe4e7;
    padding: 8px;
    vertical-align: top;
}

.legal-table tr:last-child td {
    border-bottom: 2px solid #263f55;
}

.item-description {
    color: #596771;
    margin-top: 2px;
}

.text-right {
    text-align: right !important;
}

.totals-section {
    margin-top: 12px;
}

.amount-words {
    padding-top: 5px;
}

.amount-words p {
    margin: 2px 0;
}

.totals-box {
    width: 100%;
}

.total-row {
    border-bottom: 1px solid #dfe4e7;
    display: flex;
    justify-content: space-between;
    padding: 4px 0;
}

.grand-total {
    border-bottom: 0;
    border-top: 2px solid #263f55;
    color: #263f55;
    font-size: 13px;
    margin-top: 3px;
    padding-top: 7px;
    text-transform: uppercase;
}

.invoice-notes {
    font-size: 9px;
    font-style: italic;
    margin-top: 12px;
}

.invoice-notes p,
.invoice-notes ol {
    margin: 2px 0;
}

.invoice-notes ol {
    padding-left: 18px;
}

.payment-section {
    margin-top: 12px;
}

.payment-intro {
    font-weight: 600;
    margin: 0 0 6px;
}

.payment-details {
    background: #f5f7f8;
    border-left: 3px solid #155d63;
    padding: 7px 9px;
    width: 76%;
}

.payment-details p {
    display: flex;
    margin: 2px 0;
}

.payment-details span {
    color: #596771;
    width: 145px;
}

.signature-section {
    margin-top: 22px;
    width: 190px;
}

.signature-line {
    border-top: 1px solid #263443;
    margin-bottom: 5px;
}

.signature-section strong,
.signature-section span {
    display: block;
}

#footer-html {
    background: #fff;
    border-top: 2px solid #263f55;
    bottom: 0;
    left: 0;
    padding: 8px 0 5px;
    position: absolute;
    right: 0;
    text-align: center;
    width: 100%;
}

.firm-address {
    color: #596771;
    font-size: 7px;
    line-height: 1.4;
    text-transform: uppercase;
}

.print-format .row.header-top-section,
.print-format .row.recipient-section,
.print-format .row.totals-section {
    margin-top: 0 !important;
}

.invoice-header,
.recipient-layout,
.totals-layout {
    display: -webkit-box;
    display: flex;
    width: 100%;
}

.invoice-header {
    -webkit-box-align: end;
    align-items: flex-end;
}

.firm-letterhead { width: 58%; }
.invoice-title-block { width: 42%; }
.recipient-party { padding-right: 24px; width: 62%; }
.invoice-meta { width: 38%; }
.amount-words { padding-right: 24px; width: 58%; }
.totals-wrapper { width: 42%; }
